def solve(s: String): Long = {
    val n = s.length
    var base = 0L
    var countL = 0L
    var countT = s.count(_ == 'T').toLong
    for (ch <- s) {
        ch match {
            case 'L' => countL += 1
            case 'T' => countT -= 1
            case 'C' => base += countL * countT
            case _ =>
        }
    }

    val prefixLCount = new Array[Long](n+1)
    prefixLCount(0) = 0
    for (i <- 0 until n) {
        prefixLCount(i+1) = prefixLCount(i) + (if (s(i) == 'L') 1 else 0)
    }

    val suffixTCount = new Array[Long](n+1)
    suffixTCount(n) = 0
    for (i <- n-1 downto 0) {
        suffixTCount(i) = suffixTCount(i+1) + (if (s(i) == 'T') 1 else 0)
    }

    val preLcpair = new Array[Long](n+1)
    preLcpair(0) = 0
    var countLForPair = 0L
    for (i <- 0 until n) {
        if (s(i) == 'L') {
            countLForPair += 1
            preLcpair(i+1) = preLcpair(i)
        } else if (s(i) == 'C') {
            preLcpair(i+1) = preLcpair(i) + countLForPair
        } else {
            preLcpair(i+1) = preLcpair(i)
        }
    }

    val suffixCtpair = new Array[Long](n+1)
    suffixCtpair(n) = 0
    var totalPairs = 0L
    var countTForPair = 0L
    for (i <- n-1 downto 0) {
        if (s(i) == 'T') {
            countTForPair += 1
        } else if (s(i) == 'C') {
            totalPairs += countTForPair
        }
        suffixCtpair(i) = totalPairs
    }

    var maxAdditional = 0L
    for (i <- 0 to n) {
        val insertL = suffixCtpair(i)
        val insertC = prefixLCount(i) * suffixTCount(i)
        val insertT = preLcpair(i)
        val bestAtI = math.max(insertL, math.max(insertC, insertT))
        if (bestAtI > maxAdditional) maxAdditional = bestAtI
    }

    base + maxAdditional
}
```

