def solve(s: String): Long = {
    val n = s.length
    if (n == 0) return 0L

    val left_L_count = new Array[Long](n + 1)
    left_L_count(0) = 0
    for (i <- 0 until n) {
        if (s(i) == 'L') {
            left_L_count(i + 1) = left_L_count(i) + 1
        } else {
            left_L_count(i + 1) = left_L_count(i)
        }
    }

    val right_T_count = new Array[Long](n + 1)
    right_T_count(n) = 0
    for (i <- n - 1 downto 0) {
        if (s(i) == 'T') {
            right_T_count(i) = right_T_count(i + 1) + 1
        } else {
            right_T_count(i) = right_T_count(i + 1)
        }
    }

    val totalPairs_LC_upto = new Array[Long](n + 1)
    totalPairs_LC_upto(0) = 0
    var currentL: Long = 0
    for (i <- 0 until n) {
        if (s(i) == 'L') {
            currentL += 1
            totalPairs_LC_upto(i + 1) = totalPairs_LC_upto(i)
        } else if (s(i) == 'C') {
            totalPairs_LC_upto(i + 1) = totalPairs_LC_upto(i) + currentL
        } else {
            totalPairs_LC_upto(i + 1) = totalPairs_LC_upto(i)
        }
    }

    val totalPairs_CT_from_i = new Array[Long](n + 1)
    totalPairs_CT_from_i(n) = 0
    var currentT: Long = 0
    for (i <- n - 1 downto 0) {
        if (s(i) == 'T') {
            currentT += 1
            totalPairs_CT_from_i(i) = totalPairs_CT_from_i(i + 1)
        } else if (s(i) == 'C') {
            totalPairs_CT_from_i(i) = totalPairs_CT_from_i(i + 1) + currentT
        } else {
            totalPairs_CT_from_i(i) = totalPairs_CT_from_i(i + 1)
        }
    }

    var base: Long = 0
    for (j <- 0 until n) {
        if (s(j) == 'C') {
            base += left_L_count(j) * right_T_count(j + 1)
        }
    }

    var ans = base
    for (i <- 0 to n) {
        ans = Math.max(ans, base + totalPairs_CT_from_i(i))
        ans = Math.max(ans, base + left_L_count(i) * right_T_count(i))
        ans = Math.max(ans, base + totalPairs_LC_upto(i))
    }

    ans
}
```

### Explanation
1. **Prefix Arrays**:
   - `left_L_count` tracks the cumulative count of 'L's up to each position in the string.
   - `totalPairs_LC_upto` tracks the cumulative count of "LC" pairs up to each position.
   - These arrays are built by iterating from the start to the end of the string.

2. **Suffix Arrays**:
   - `right_T_count` tracks the cumulative count of 'T's from each position to the end of the string.
   - `totalPairs_CT_from_i` tracks the cumulative count of "CT" pairs from each position to the end.
   - These arrays are built by iterating from the end to the start of the string.

3. **Base Count Calculation**:
   - For each 'C' in the string, the base count of "LCT" subsequences is incremented by the product of the number of 'L's before the 'C' and the number of 'T's after the 'C'.

4. **Insertion Evaluation**:
   - For each possible insertion position, the solution evaluates the potential increase in "LCT" subsequences by inserting 'L', 'C', or 'T':
     - Inserting 'L' increases the count by the number of "CT" pairs after the insertion.
     - Inserting 'C' increases the count by the product of 'L's before and 'T's after the insertion.
     - Inserting 'T' increases the count by the number of "LC" pairs before the insertion.
   - The maximum value obtained from these evaluations and the base count is returned as the result.

This approach efficiently computes the maximum number of "LCT" subsequences by leveraging prefix and suffix arrays to avoid recalculating counts for each insertion scenario, ensuring optimal performance even for large strings.
